def forward_chaining(rule_base, working_memory):
 while True:
 changed = False
 for rule in rule_base:
 if all(condition in working_memory for condition in rule['conditions']):
 conclusion = rule['conclusion']
 if conclusion not in working_memory:
 working_memory.append(conclusion)
 changed = True
 if not changed:
 break
 return working_memory

# Example usage:
rule_base = [
 {'conditions': ['has fur'], 'conclusion': 'is a mammal'},
 {'conditions': ['is a mammal', 'eats meat'], 'conclusion': 'is a carnivore'}
]
working_memory = ['has fur', 'eats meat']
print(forward_chaining(rule_base, working_memory))

def backward_chaining(rule_base, goal):
 if goal in rule_base:
 return True
 for rule in rule_base:
 if rule['conclusion'] == goal:
 return all(backward_chaining(rule_base, condition) for condition in rule['conditions'])
 return False

# Example usage:
rule_base = [
 {'conditions': ['has fur'], 'conclusion': 'is a mammal'},
 {'conditions': ['is a mammal', 'eats meat'], 'conclusion': 'is a carnivore'}
]
goal = 'is a carnivore'
print(backward_chaining(rule_base, goal))
